import React from "react";

export default function Spinner({ size = 24, color = "#00bcd4" }) {
  return (
    <span
      style={{
        display: "inline-block",
        width: size,
        height: size,
        border: `3px solid rgba(0,188,212,0.2)`,
        borderTop: `3px solid ${color}`,
        borderRadius: "50%",
        animation: "spin 0.7s linear infinite",
      }}
      role="status"
      aria-label="Loading"
    />
  );
}
